    const s = new Error().stack;
    if (!s) return '?';
    const lines = s.split('\n');
    const line = (lines[3] || lines[2] || lines[1] || '').trim();
    let m = line.match(/at\s+([^\s(]+)\s*\(([^)]*):(\d+):\d+\)/); // "at nombre (url:LINEA:COL)"
    if (m) return m[1] + ':' + m[3];
    m = line.match(/at\s+([^\s(]+):(\d+):\d+/); // función anónima: "at url:LINEA:COL"
