// marcan `true` explícitamente en puntos concretos del código (edPushHistory,
// edApplyHistory, edSetOrientation, sesiones de dibujo/vectorial, rotar hoja
// no activa, reparación de IDs). Se combinan con los contadores: una página
// se considera sucia si CUALQUIERA de los mecanismos lo indica.
//
// window._edPagesStructureDirtyLocal / …Cloud: true si han cambiado el
// NÚMERO o el ORDEN de las páginas desde el último guardado de ese tipo
// (añadir, eliminar, reordenar, duplicar hoja) — incluye la ELIMINACIÓN de
// hojas, para que una hoja borrada no reaparezca al cargar la obra: mientras
// esté a true, el guardado correspondiente ignora los contadores/flags por
// página y hace SIEMPRE un guardado completo, que en la ruta de nube borra
// primero todos los panels existentes y sube solo los que hay ahora mismo.
//
// Principio de diseño: ante la duda, marcar sucio. Saltarse una página que sí
// cambió sería pérdida de datos; volver a guardar una página que no cambió
// solo cuesta un poco de tiempo — exactamente lo que ya pasaba antes de este
// cambio en TODAS las páginas.
function _edMarkPageDirty(pageOrIdx) {
  // Mientras la obra se esté cargando (contador bloqueante de my-comics
  // activo), nada de lo que ocurra internamente puede ser una edición real
  // del usuario — ya existe un bloqueo que impide tocar nada hasta que
  // termine de cargar. Sin esto, el propio edLoadProject marcaba la página
  // activa como sucia (vía su empuje inicial al historial) justo después de
  // establecerla como "limpia" momentos antes, en la misma carga — lo que
  // forzaba una reserialización innecesaria en el primer guardado de cada
  // sesión, aunque el usuario no hubiera tocado nada todavía.
  if (window._edLoadingSuppressDirty) return;
  const p = (typeof pageOrIdx === 'number') ? edPages[pageOrIdx] : pageOrIdx;
  if (p) { p._dirtyLocal = true; p._dirtyCloud = true; }
}
function _edMarkPagesStructureDirty() {
  if (window._edLoadingSuppressDirty) return;
  window._edPagesStructureDirtyLocal = true;
  window._edPagesStructureDirtyCloud = true;
}
// Elementos donde un tap/click NUNCA puede modificar el contenido de la obra
// — se excluyen del contador de interacción. Deliberadamente es una lista
// CORTA y de exclusión (no de inclusión): cualquier botón de menú que NO
// esté aquí sigue contando, porque podría crear/mover/eliminar contenido
// (reordenar capas, añadir hoja, crear una animación, borrar de la
// biblioteca...) y no tengo forma de estar seguro de cuáles son inofensivos
// sin revisar cada uno. Ante la duda, contar.
const _ED_TICK_EXCLUDE_SELECTOR = [
  '#edPagePrev', '#edPageNext',   // navegar entre hojas para verlas, no las modifica
  '.ed-nav-page-btn',             // miniaturas del navegador desplegable de páginas — mismo motivo
  '.ed-page-thumb',               // miniatura del panel completo de páginas — mismo motivo
  '#edPagesClose',                // cerrar el panel completo de páginas (no modifica nada)
  '#edMinimizeBtn',               // ocultar/mostrar menú
  '#edSaveBtn', '#edCloudSaveBtn',// guardar (el propio guardado ya tiene su seguimiento)
  '#edPreviewBtn',                // vista previa / reproducir
  '#edFsBtn',                     // pantalla completa
  '#edDiagBtn',                   // diagnóstico
  '#edHelpRefModal',              // ventana de ayuda entera (contenido, cerrar, "no volver a mostrar")
].join(', ');
// Listener global de "cualquier tap/click", con las excepciones de arriba.
// No comprueba si el gesto se completó o se canceló: basta con haber
// empezado un tap/click fuera de la lista de exclusión para marcar la
// página activa como potencialmente modificada, en ambos contadores.
function _edInteractionTick(e) {
  // Un toque impaciente sobre el propio contador de carga (mientras la obra
  // todavía se está cargando) no puede modificar nada — ver nota en
  // _edMarkPageDirty. El overlay ya bloquea visualmente la interacción; esto
  // cierra el hueco de que el listener global (fase de captura) lo cuente de
  // todas formas.
  if (window._edLoadingSuppressDirty) return;
  const _target = e && e.target;
  if (_target && _target.closest) {
    if (_target.closest(_ED_TICK_EXCLUDE_SELECTOR)) return;
  }
  // Tap que no aterriza en ningún elemento reconocido (fuera del canvas y
  // fuera de cualquier botón/panel) — no puede modificar nada.
  if (_target === document.body || _target === document.documentElement) return;
  const p = edPages[edCurrentPage];
  if (!p) return;
  p._dirtyCountLocal = (p._dirtyCountLocal || 0) + 1;
  p._dirtyCountCloud = (p._dirtyCountCloud || 0) + 1;
}
// ¿Está sucia esta página para guardado LOCAL?
function _edPageDirtyLocal(p) {
  if (!p) return true;
  if (p._dirtyLocal !== false) return true;
  if (typeof p._dirtyCountLocal !== 'number') return true; // nunca establecido → sucia por defecto
  return p._dirtyCountLocal !== 0;
}
// ¿Está sucia esta página para guardado en NUBE? (contador independiente)
function _edPageDirtyCloud(p) {
  if (!p) return true;
  if (p._dirtyCloud !== false) return true;
  if (typeof p._dirtyCountCloud !== 'number') return true; // nunca establecido → sucia por defecto
  return p._dirtyCountCloud !== 0;
}

function edPushHistory(force, movedLayer){
  // Actualizar indicador de tamaño con debounce (no bloquea el flujo)
  clearTimeout(window._edSizeCheckTimer);
  window._edSizeCheckTimer = setTimeout(_edSizeCheck, 800);
  // Autosave diferido — no bloquear el flujo de historia
  clearTimeout(window._edAutosavePushTimer);
  window._edAutosavePushTimer = setTimeout(_edAutosaveWrite, 5000);
  // Durante una sesión de dibujo a mano activa, bloquear push global (salvo force=true).
  // La flag _edDrawSessionActive se activa en _edDrawInitHistory y se desactiva al congelar.
  if(!force && window._edDrawSessionActive){
    window._edHistDiag = window._edHistDiag||[];
    window._edHistDiag.push('BLOCKED_DRAW_SESSION');
    return;
  }
  // Durante una sesión vectorial activa, bloquear push al historial global.
  // Solo la apertura del panel ("antes") y el OK ("después") deben registrarse.
  // Los estados intermedios solo van al historial vectorial local (_vs*).
  // Si _vsHistory activo pero no hay shape/line seleccionada, limpiar (sesión vectorial huérfana)
  if(_vsHistory.length > 0){
    const _curL = edSelectedIdx>=0 ? edLayers[edSelectedIdx] : null;
    if(!_curL || (_curL.type!=='shape' && _curL.type!=='line')){
      _vsHistory=[]; _vsHistIdx=-1; // limpiar sesión vectorial huérfana
    } else {
      window._edHistDiag=window._edHistDiag||[]; window._edHistDiag.push('BLOCKED_VS vsLen='+_vsHistory.length); edUpdateUndoRedoBtns(); return;
    }
  }
  const layersJSON = _edLayersSnapshot(movedLayer);
  // DIAG: registrar cada push
  if(window._edHistDiag) window._edHistDiag.push('push force='+force+' layers='+JSON.parse(layersJSON).length+' total_antes='+edHistory.length);

  if(!force && edHistory.length > 0 && edHistoryIdx >= 0){
    const last = edHistory[edHistoryIdx];
    if(last.layersJSON === layersJSON){ window._edHistDiag=window._edHistDiag||[]; window._edHistDiag.push('SKIP_SAME_JSON len='+layersJSON.length); edUpdateUndoRedoBtns(); return; }
  }

  edHistory = edHistory.slice(0, edHistoryIdx + 1);
  edHistory.push({ pageIdx: edCurrentPage, layersJSON,
    groupRot: edMultiGroupRot,
    multiSel: edMultiSel.length ? [...edMultiSel] : [] });
  if(edHistory.length > ED_MAX_HISTORY) edHistory.shift();
  edHistoryIdx = edHistory.length - 1;
  _edMarkPageDirty(edCurrentPage);
  edUpdateUndoRedoBtns();
}

function edUndo(){
  if(_edLoadProjectInProgress){ edToast('Cargando...'); return; }
  if(edHistoryIdx <= 0){ edToast('Nada que deshacer'); return; }
  // Verificar que el snapshot al que vamos tiene layers (no es un estado vacío de carga)
  const _prevSnap = edHistory[edHistoryIdx - 1];
  if(!_prevSnap || !_prevSnap.layersJSON) { edToast('Nada que deshacer'); return; }
  const _prevLayers = JSON.parse(_prevSnap.layersJSON);
  // No bloquear deshacer a estado vacío — es válido (canvas antes del primer objeto)
  edHistoryIdx--;
  edApplyHistory(edHistory[edHistoryIdx]);
}

function edRedo(){
  if(_edLoadProjectInProgress){ edToast('Cargando...'); return; }
  if(edHistoryIdx >= edHistory.length - 1){ edToast('Nada que rehacer'); return; }
  edHistoryIdx++;
  edApplyHistory(edHistory[edHistoryIdx]);
}

function edApplyHistory(snapshot){
  if(!snapshot) return;
  // Deshacer/rehacer también deja el contenido de la página distinto de lo
  // guardado — edPushHistory no se llama en este camino, así que hay que
  // marcar sucio aquí explícitamente (si no, un guardado posterior podría
  // reutilizar por error la versión "de después" ya guardada en vez de
  // reflejar el "antes" al que se acaba de volver).
  _edMarkPageDirty(snapshot.pageIdx);
  const raw = JSON.parse(snapshot.layersJSON);
  const imgPromises = [];
  edLayers = raw.map(o => {
    let l;
    if     (o.type === 'text')   l = new TextLayer(o.text, o.x, o.y);
    else if(o.type === 'bubble') l = new BubbleLayer(o.text, o.x, o.y);
    else if(o.type === 'image') {
      // Buscar layer vivo con la misma _uid o animKey para preservar _pngFrames/_apngSrc
      const _rawIdx = raw.indexOf(o);
      const _curPage = edPages[snapshot.pageIdx];
      const _liveLayers = _curPage ? _curPage.layers : edLayers;
      const _liveImg = _liveLayers?.find(lv =>
        lv && lv.type === 'image' && (
          (o._uid && lv._uid === o._uid) ||
          (o.animKey && lv.animKey === o.animKey) ||
          (o._pngFramesKey && lv._pngFramesKey === o._pngFramesKey)
        )
      );
      l = new ImageLayer(null, o.x, o.y);
      // Preservar datos de animación del layer vivo
      if (_liveImg) {
        if (_liveImg._pngFrames) l._pngFrames = _liveImg._pngFrames;
        if (_liveImg._apngSrc)   l._apngSrc   = _liveImg._apngSrc;
        if (_liveImg._animOc)    l._animOc     = _liveImg._animOc;
        if (_liveImg._animReady) l._animReady  = _liveImg._animReady;
        if (_liveImg.img)        l.img         = _liveImg.img;
      }
    }
    else if(o.type === 'draw') {
      const _isV = (edPages[snapshot.pageIdx]?.orientation||edOrientation)==='vertical';
      l = o.dataUrl ? DrawLayer.fromDataUrl(o.dataUrl, _isV?ED_PAGE_W:ED_PAGE_H, _isV?ED_PAGE_H:ED_PAGE_W)
                    : new DrawLayer();
      if(o.locked) l.locked = true;
      if(o.hidden) l.hidden = true;
      if(o.groupId) l.groupId = o.groupId;
      if(o._uid) l._uid=o._uid;
      if(o._fillLayerId) l._fillLayerId=o._fillLayerId;
      return l;
    }
    else if(o.type === 'stroke') {
      const _isV = (edPages[snapshot.pageIdx]?.orientation||edOrientation)==='vertical';
      const _pw = _isV?ED_PAGE_W:ED_PAGE_H, _ph = _isV?ED_PAGE_H:ED_PAGE_W;
      // Strokes antiguos (sin x/y/width/height) usan bbox completo de página
      const _lsx = o.x != null ? o.x : 0.5;
      const _lsy = o.y != null ? o.y : 0.5;
      const _lsw = o.width  != null ? o.width  : 1.0;
      const _lsh = o.height != null ? o.height : 1.0;
      // Reconstruir stroke: buscar primero si el layer vivo actual tiene el mismo
      // dataUrl y reusar su canvas ya pintado (evita parpadeo/invisibilidad).
      // Solo reconstruir desde dataUrl si no hay canvas vivo reutilizable.
      { const _bw = Math.max(1, Math.round(_lsw * _pw));
        const _bh = Math.max(1, Math.round(_lsh * _ph));
        // Buscar canvas vivo en la misma posición del array de la página actual
        // (mismo índice y tipo stroke) para reusar sin comparar dataUrl (costoso).
        const _curPage = edPages[snapshot.pageIdx];
        const _rawIdx = raw.indexOf(o);
        const _liveAtIdx = (_curPage?.layers||[])[_rawIdx];
        const _liveSrc = (_liveAtIdx && _liveAtIdx.type === 'stroke' &&
          _liveAtIdx._canvas && _liveAtIdx._canvas.width === _bw &&
          _liveAtIdx._canvas.height === _bh) ? _liveAtIdx : null;
        l = new StrokeLayer(document.createElement('canvas'), _pw, _ph);
        l.x = _lsx; l.y = _lsy; l.width = _lsw; l.height = _lsh;
        if(_liveSrc) {
          // Reusar canvas ya pintado — visible inmediatamente sin carga async
          l._canvas = _liveSrc._canvas;
        } else {
          const _sc = document.createElement('canvas');
          _sc.width = _bw; _sc.height = _bh;
          l._canvas = _sc;
          if(o.dataUrl) {
            const _lRef = l;
            imgPromises.push(new Promise(res => {
              const _si = new Image();
              _si.onload = () => { _lRef._canvas.getContext('2d').drawImage(_si, 0, 0, _bw, _bh); res(); };
              _si.onerror = () => res();
              _si.src = o.dataUrl;
            }));
          }
        }
      }
      if(o.frozenLine) l._frozenLine = o.frozenLine;
      if(o.rotation) l.rotation=o.rotation;
      if(o.opacity !== undefined) l.opacity=o.opacity;
      if(o.groupId) l.groupId=o.groupId;
      if(o.locked) l.locked=true;
      if(o.hidden) l.hidden=true;
      if(o._uid) l._uid=o._uid;
      if(o._fillLayerId) l._fillLayerId=o._fillLayerId;
      if(o._pencilLayerId) l._pencilLayerId=o._pencilLayerId;
      if(o._watercolorLayerId) l._watercolorLayerId=o._watercolorLayerId;
      // Restaurar recorrido de animación
      if(o._motionPath){l._motionPath=o._motionPath;l._motionPathClosed=o._motionPathClosed||false;l._motionSpeed=o._motionSpeed;l._motionPathEnd=o._motionPathEnd;l._motionPathAccel=o._motionPathAccel;l._motionPathOrient=o._motionPathOrient||false;} else{delete l._motionPath;delete l._motionPathClosed;delete l._motionSpeed;delete l._motionPathEnd;delete l._motionPathAccel;delete l._motionPathOrient;}
      return l;
    }
    else if(o.type === 'shape') {
      l = new ShapeLayer(o.shape||'rect', o.x||0.5, o.y||0.5, o.width||0.3, o.height||0.2);
      l.color=o.color||'#000'; l.fillColor=o.fillColor||'none'; l.lineWidth=o.lineWidth??3; l.rotation=o.rotation||0; l.opacity=o.opacity??1;
      if(o.cornerRadius) l.cornerRadius=o.cornerRadius;
      if(o.cornerRadii) l.cornerRadii = Array.isArray(o.cornerRadii) ? [...o.cornerRadii] : {...o.cornerRadii};
      if(o.grouped) l.grouped = true;
      if(o.groupedStyles) l.groupedStyles = o.groupedStyles.map(s=>({...s}));
      if(o.groupId) l.groupId=o.groupId;
      if(o.locked) l.locked=true;
      if(o.hidden) l.hidden=true;
      // Restaurar recorrido de animación
      if(o._motionPath){l._motionPath=o._motionPath;l._motionPathClosed=o._motionPathClosed||false;l._motionSpeed=o._motionSpeed;l._motionPathEnd=o._motionPathEnd;l._motionPathAccel=o._motionPathAccel;l._motionPathOrient=o._motionPathOrient||false;} else{delete l._motionPath;delete l._motionPathClosed;delete l._motionSpeed;delete l._motionPathEnd;delete l._motionPathAccel;delete l._motionPathOrient;}
      return l;
    }
    else if(o.type === 'line') {
      l = new LineLayer();
      l.points=o.points||[]; l.closed=o.closed||false;
      l.color=o.color||'#000'; l.fillColor=o.fillColor||'#ffffff'; l.lineWidth=o.lineWidth??3; l.opacity=o.opacity??1;
      l.rotation=o.rotation||0;
      if(o.cornerRadii) l.cornerRadii = Array.isArray(o.cornerRadii) ? [...o.cornerRadii] : {...o.cornerRadii};
      if(o.subPaths&&o.subPaths.length) l.subPaths = o.subPaths.map(sp=>{const _s=sp.slice(); if(sp.cornerRadii)_s.cornerRadii={...sp.cornerRadii}; return _s;});
      if(o.x!=null){l.x=o.x;l.y=o.y;l.width=o.width||0.01;l.height=o.height||0.01;}
      else l._updateBbox();
      if(o.groupId) l.groupId=o.groupId;
      if(o.locked) l.locked=true;
      if(o.hidden) l.hidden=true;
      // Restaurar recorrido de animación
      if(o._motionPath){l._motionPath=o._motionPath;l._motionPathClosed=o._motionPathClosed||false;l._motionSpeed=o._motionSpeed;l._motionPathEnd=o._motionPathEnd;l._motionPathAccel=o._motionPathAccel;l._motionPathOrient=o._motionPathOrient||false;} else{delete l._motionPath;delete l._motionPathClosed;delete l._motionSpeed;delete l._motionPathEnd;delete l._motionPathAccel;delete l._motionPathOrient;}
      return l;
    }
    else if(o.type === 'fill') {
      const fl = new FillLayer();
      if(o._drawLayerId) fl._drawLayerId = o._drawLayerId;
      if(o._uid) fl._uid = o._uid;
      if(o.hidden) fl.hidden = o.hidden;
      if(o.locked) fl.locked = o.locked;
      if(o.opacity !== undefined) fl.opacity = o.opacity;
      if(o.x != null) { fl.x=o.x; fl.y=o.y; fl.width=o.width||1; fl.height=o.height||1; fl.rotation=o.rotation||0; }
      if(o.dataUrl) {
        // Determinar si el fill era workspace (DrawLayer activo) o local (StrokeLayer)
        const _wasWS = o._isWorkspaceCanvas === true;
        if (_wasWS) {
          // Fill workspace: canvas ED_CANVAS_W × ED_CANVAS_H
          fl._canvas.width  = ED_CANVAS_W;
          fl._canvas.height = ED_CANVAS_H;
          fl._ctx = fl._canvas.getContext('2d');
          fl._isWorkspaceCanvas = true;
          fl.x=0.5; fl.y=0.5; fl.width=1; fl.height=1; fl.rotation=0;
        } else {
          // Fill local: canvas bbox (width*pw × height*ph)
          const _isV = (edPages[snapshot.pageIdx]?.orientation||edOrientation)==='vertical';
          const _rpw = _isV ? ED_PAGE_W : ED_PAGE_H;
          const _rph = _isV ? ED_PAGE_H : ED_PAGE_W;
          const _rw = Math.max(1, Math.round((o.width||1) * _rpw));
          const _rh = Math.max(1, Math.round((o.height||1) * _rph));
          fl._canvas.width  = _rw;
          fl._canvas.height = _rh;
          fl._ctx = fl._canvas.getContext('2d');
          fl._isWorkspaceCanvas = false;
        }
        imgPromises.push(new Promise(res => {
          const _fi = new Image();
          _fi.onload = () => {
            fl._ctx.clearRect(0, 0, fl._canvas.width, fl._canvas.height);
            fl._ctx.drawImage(_fi, 0, 0, fl._canvas.width, fl._canvas.height);
            res();
          };
          _fi.onerror = () => res();
          _fi.src = o.dataUrl;
        }));
      }
      return fl;
    }
    else if(o.type === 'pencil' || o.type === 'watercolor') {
      const _LayerCls = o.type === 'pencil' ? PencilLayer : WatercolorLayer;
      const _gl = new _LayerCls();
      if(o._drawLayerId) _gl._drawLayerId = o._drawLayerId;
      if(o._uid) _gl._uid = o._uid;
      if(o.hidden) _gl.hidden = o.hidden;
      if(o.locked) _gl.locked = o.locked;
      if(o.opacity !== undefined) _gl.opacity = o.opacity;
      if(o.x != null) { _gl.x=o.x; _gl.y=o.y; _gl.width=o.width||1; _gl.height=o.height||1; _gl.rotation=o.rotation||0; }
      if(o.dataUrl) {
        const _wasWS = o._isWorkspaceCanvas === true;
        if (_wasWS) {
          _gl._canvas.width  = ED_CANVAS_W;
          _gl._canvas.height = ED_CANVAS_H;
          _gl._ctx = _gl._canvas.getContext('2d');
          _gl._isWorkspaceCanvas = true;
          _gl.x=0.5; _gl.y=0.5; _gl.width=1; _gl.height=1; _gl.rotation=0;
        } else {
          const _isV = (edPages[snapshot.pageIdx]?.orientation||edOrientation)==='vertical';
          const _rpw = _isV ? ED_PAGE_W : ED_PAGE_H;
          const _rph = _isV ? ED_PAGE_H : ED_PAGE_W;
          const _rw = Math.max(1, Math.round((o.width||1) * _rpw));
          const _rh = Math.max(1, Math.round((o.height||1) * _rph));
          _gl._canvas.width  = _rw;
          _gl._canvas.height = _rh;
          _gl._ctx = _gl._canvas.getContext('2d');
          _gl._isWorkspaceCanvas = false;
        }
        imgPromises.push(new Promise(res => {
          const _gi = new Image();
          _gi.onload = () => { _gl._ctx.clearRect(0,0,_gl._canvas.width,_gl._canvas.height); _gl._ctx.drawImage(_gi,0,0,_gl._canvas.width,_gl._canvas.height); res(); };
          _gi.onerror = () => res();
          _gi.src = o.dataUrl;
        }));
      }
      return _gl;
    }
    else if(o.type === 'group') return null; // obsoleto
    else if(o.type === 'gif') {
      l = new GifLayer(null, o.x||0.5, o.y||0.5, o.width||0.3, o.height||0.3);
    }
    else return o;
    for(const k of Object.keys(o)){
      if(k !== '_imgSrc') l[k] = o[k];
    }
    if(o._imgSrc){
      const p = new Promise(resolve => {
        const img = new Image();
        img.onload  = () => {
          l.img = img;
          resolve();
        };
        img.onerror = () => resolve();
        img.src = o._imgSrc;
      });
      imgPromises.push(p);
    }
    // Restaurar animación APNG desde IDB
    if(o.type === 'image' && (o.animKey || o._pngFramesKey || o._apngIdbKey)) {
      const _ak = o._pngFramesKey || o.animKey || o._apngIdbKey;
      if(_ak && window._sbAnimIdbLoad) {
        window._sbAnimIdbLoad(_ak).then(data => {
          if(!data) return;
          if(typeof data === 'string') l._apngSrc = data;
          else if(Array.isArray(data) && data.length) l._pngFrames = data;
          if(l._apngSrc || l._pngFrames) {
            const _wasPlaying = o._playing || false;
            l.loadAnim(l._apngSrc || l._pngFrames, () => {
              l._playing = _wasPlaying;
              if(_wasPlaying) l._applyFrame(l._fIdx || 0);
              edRedraw();
            });
          }
        }).catch(() => {});
      }
    }
    // Restaurar gif desde IDB
    if(o.type === 'gif' && o.gifKey && typeof _gifIdbLoad === 'function') {
      const _gifWasPlaying = o._playing || false;
      _gifIdbLoad(o.gifKey).then(dataUrl => {
        if(dataUrl) {
          l._gifDataUrl = dataUrl;
          l.load(dataUrl, () => {
            l._playing = _gifWasPlaying;
            if(_gifWasPlaying) { l._applyFrame(0); }
            edRedraw();
          });
        }
      }).catch(() => {});
    }
    return l;
  });
  if(edPages[snapshot.pageIdx]){
    edPages[snapshot.pageIdx].layers = edLayers;
  }
  // Restaurar rotación del grupo y selección múltiple
  edMultiGroupRot = snapshot.groupRot || 0;
  if(snapshot.multiSel && snapshot.multiSel.length >= 2){
    edMultiSel = snapshot.multiSel.filter(i => i < edLayers.length);
    _msRecalcBbox();
    edActiveTool = 'multiselect';
  } else {
    edMultiSel = []; edMultiBbox = null;
  }
  edSelectedIdx = -1;
  edPanelUserClosed = false;
  edUpdateUndoRedoBtns();
  // Navegar a la página del snapshot si es distinta a la actual
  if(snapshot.pageIdx !== edCurrentPage && edPages[snapshot.pageIdx]){
    edCurrentPage = snapshot.pageIdx;
    edLayers = edPages[edCurrentPage].layers;
    const _po = edPages[edCurrentPage].orientation || 'vertical';
    if(_po !== edOrientation) edOrientation = _po;
    edUpdateNavPages();
  }
  Promise.all(imgPromises).then(() => edRedraw());
}

function edUpdateUndoRedoBtns(){
  const u = $('edUndoBtn'), r = $('edRedoBtn');
  if(u) u.disabled = edHistoryIdx <= 0;
  if(r) r.disabled = edHistoryIdx >= edHistory.length - 1;

}

/* ── edFitCanvas ──────────────────────────────────────────────────
   Ajusta las barras de UI y el tamaño del canvas DOM al viewport.
   El canvas ocupa SIEMPRE todo el área disponible (sin scroll CSS).
   La cámara (edCamera) controla qué parte del workspace se ve.
   ──────────────────────────────────────────────────────────────── */
function edFitCanvas(resetCamera){
  if(!edCanvas) return;
  // Preservar cámara salvo reset explícito autorizado por el usuario
  const _savedCam = {x:edCamera.x, y:edCamera.y, z:edCamera.z};
  const _doReset = resetCamera && window._edUserRequestedReset;

  const topbar=$('edTopbar'), menu=$('edMenuBar'), opts=$('edOptionsPanel');

  const topH  = (!edMinimized && topbar)  ? topbar.getBoundingClientRect().height  : 0;
  const menuH = (!edMinimized && menu)    ? menu.getBoundingClientRect().height    : 0;
  // Si el panel está colapsado (panel-collapsed), su altura efectiva es 0 aunque tenga 'open'
  const _optsCollapsed = opts && opts.classList.contains('panel-collapsed');
  const optsH = (opts && opts.classList.contains('open') && !_optsCollapsed && opts.style.visibility !== 'hidden') ? opts.getBoundingClientRect().height : 0;
  if(menu && !edMinimized) menu.style.top = topH + 'px';
  if(opts) opts.style.top = (topH + menuH) + 'px';
  const totalBarsH = topH + menuH + optsH;

  const availW = window.innerWidth;
  const availH = window.innerHeight - totalBarsH;

  const newW = Math.round(availW);
  const newH = Math.round(availH);

  // Detectar cambio de VENTANA (no de panel de opciones)
  // _edWinW/_edWinH solo cambian con resize de ventana real
  // Actualizar dimensiones conocidas — sin resetear cámara automáticamente
  // La cámara solo se resetea cuando se pide explícitamente (primera carga, lupa, orientación)
  window._edWinW = window.innerWidth;
  window._edWinH = window.innerHeight;

  // Redimensionar canvas si es necesario
  const _prevW = edCanvas.width, _prevH = edCanvas.height;
  const _sizeChanged = _prevW !== newW || _prevH !== newH;
  if(_sizeChanged){
    edCanvas.width  = newW;
    edCanvas.height = newH;
    // Compensar cámara en ambas direcciones para que el contenido no salte visualmente
    // cuando el panel de opciones se abre o se colapsa.
    if(!_doReset){
      _savedCam.y -= (_prevH - newH); // negativo si crece (panel cierra), positivo si encoge (panel abre)
    }
  }
  edCanvas.style.width  = newW + 'px';
  edCanvas.style.height = newH + 'px';
  edCanvas.style.position = 'absolute';
  edCanvas.style.left = '0';
  edCanvas.style.top  = totalBarsH + 'px';
  _edCanvasTop = totalBarsH; // cachear para edCoords
  // Sincronizar gcpCanvas si está activo — mismo top que edCanvas
  if (window._gcpActive && gcpCanvas) {
    gcpCanvas.width  = newW;
    gcpCanvas.height = newH;
    gcpCanvas.style.width  = newW + 'px';
    gcpCanvas.style.height = newH + 'px';
    gcpCanvas.style.top    = totalBarsH + 'px'; // mismo top que edCanvas
  }
  edCanvas.style.margin = '0';
  // Mantener el canvas de dibujo libre sincronizado en posición y tamaño
  if(edDrawCanvas){
    const _sizeChangedDraw = edDrawCanvas.width !== newW || edDrawCanvas.height !== newH;
    if(_sizeChangedDraw){ edDrawCanvas.width = newW; edDrawCanvas.height = newH; }
    edDrawCanvas.style.width  = newW + 'px';
    edDrawCanvas.style.height = newH + 'px';
    edDrawCanvas.style.position = 'absolute';
    edDrawCanvas.style.left = '0';
    edDrawCanvas.style.top  = totalBarsH + 'px';
    edDrawCanvas.style.margin = '0';
  }

  if(_doReset){
    window._edUserRequestedReset = false;
    _edCameraReset();
  } else {
    // Restaurar cámara — el resize del canvas no debe moverla
    edCamera.x = _savedCam.x;
    edCamera.y = _savedCam.y;
    edCamera.z = _savedCam.z;
  }
  _edScrollbarsUpdate();
  // Siempre redibujar tras ajustar el canvas
  edRedraw();
}

/* ── Recentra el canvas como la lupa: ajusta cámara al lienzo y redibuja ── */
function _edResetCameraToFit(){
  window._edUserRequestedReset = true;
  edFitCanvas(true);
  if (window._gcpActive && typeof _gcpRedraw === 'function') _gcpRedraw();
}

/* ── Resetea la cámara para que el LIENZO ocupe el viewport centrado ── */
function _edCameraReset(){

  const pw = edPageW(), ph = edPageH();
  const availW = edCanvas.width, availH = edCanvas.height;
  const scaleW = availW / pw;
  const scaleH = availH / ph;
  const z = Math.min(scaleW, scaleH);
  // Posición: el centro del lienzo (en workspace) queda en el centro de pantalla
  // centro_workspace_x = edMarginX + pw/2
  // pantalla_x = centro_workspace_x * z + camera.x = availW/2
  // => camera.x = availW/2 - (edMarginX + pw/2) * z
  edCamera.z = z;
  edCamera.x = availW/2  - (edMarginX() + pw/2) * z;
  edCamera.y = availH/2  - (edMarginY() + ph/2) * z;
}

/* ══════════════════════════════════════════
   REDRAW
   ══════════════════════════════════════════ */
/* ══════════════════════════════════════════
   MULTI-SELECCIÓN — helpers
   ══════════════════════════════════════════ */

// AABB axis-aligned que engloba todos los objetos de edMultiSel
function _msBBox(){
  if(!edMultiSel.length) return null;
  const pw=edPageW(), ph=edPageH();
  let x0=Infinity,y0=Infinity,x1=-Infinity,y1=-Infinity;
  for(const i of edMultiSel){
    const la=edLayers[i]; if(!la) continue;
    const rot=(la.rotation||0)*Math.PI/180;
    const hw=la.width/2, hh=la.height/2;
    for(const [cx,cy] of [[-hw,-hh],[hw,-hh],[-hw,hh],[hw,hh]]){
      const wx=cx*pw, wy=cy*ph;
      const rx=(wx*Math.cos(rot)-wy*Math.sin(rot))/pw;
      const ry=(wx*Math.sin(rot)+wy*Math.cos(rot))/ph;
      x0=Math.min(x0,la.x+rx); y0=Math.min(y0,la.y+ry);
      x1=Math.max(x1,la.x+rx); y1=Math.max(y1,la.y+ry);
    }
  }
  return {cx:(x0+x1)/2, cy:(y0+y1)/2, w:x1-x0, h:y1-y0, x0,y0,x1,y1};
}

// 8 handles de escala del bbox colectivo (coords norm)
function _msHandles(bb){
  const {cx,cy,w,h}=bb;
  return[
    {x:cx-w/2,y:cy-h/2,c:'tl'},{x:cx+w/2,y:cy-h/2,c:'tr'},
    {x:cx-w/2,y:cy+h/2,c:'bl'},{x:cx+w/2,y:cy+h/2,c:'br'},
    {x:cx,    y:cy-h/2,c:'mt'},{x:cx,    y:cy+h/2,c:'mb'},
    {x:cx-w/2,y:cy,    c:'ml'},{x:cx+w/2,y:cy,    c:'mr'},
  ];
}

// Dibuja bbox + handles de escala + handle de rotación idéntico al individual
function edDrawMultiSel(){
  if(!edMultiSel.length || !edMultiBbox) return;
  const pw=edPageW(),ph=edPageH(),z=edCamera.z;
  const lw=1/z, hr=6/z, hrRot=8/z;
  // Siempre usar edMultiBbox (estado persistente mantenido por _msRecalcBbox).
  // Durante resize activo: escalar dimensiones por los factores del gesto.
  const bb = {
    cx: edMultiBbox.cx,
    cy: edMultiBbox.cy,
    w: edMultiResizing && edMultiTransform
      ? edMultiBbox.w * (edMultiTransform._curSx ?? 1)
      : edMultiBbox.w,
    h: edMultiResizing && edMultiTransform
      ? edMultiBbox.h * (edMultiTransform._curSy ?? 1)
      : edMultiBbox.h,
  };

  edCtx.save();
  // Contornos individuales suaves
  for(const i of edMultiSel){
    const la=edLayers[i]; if(!la) continue;
    const rot=(la.rotation||0)*Math.PI/180;
    const cx=edMarginX()+la.x*pw, cy=edMarginY()+la.y*ph;
    const w=la.width*pw, h=la.height*ph;
    edCtx.save();
    edCtx.translate(cx,cy); edCtx.rotate(rot);
    edCtx.strokeStyle='rgba(26,140,255,0.4)';
    edCtx.lineWidth=lw; edCtx.setLineDash([4/z,3/z]);
    edCtx.strokeRect(-w/2,-h/2,w,h);
    edCtx.setLineDash([]);
    edCtx.restore();
  }
  // Bbox colectivo — dibujado en espacio local (translate+rotate) igual que el individual
  const grRad = edMultiGroupRot * Math.PI / 180;
  const gcx = edMarginX()+bb.cx*pw, gcy = edMarginY()+bb.cy*ph;
  const bw=bb.w*pw, bh=bb.h*ph;

  edCtx.save();
  edCtx.translate(gcx, gcy);
  edCtx.rotate(grRad);

  // Marco del bbox
  edCtx.strokeStyle='#1a8cff'; edCtx.lineWidth=1.5/z;
  edCtx.setLineDash([6/z,3/z]);
  edCtx.strokeRect(-bw/2, -bh/2, bw, bh);
  edCtx.setLineDash([]);

  // Handles de escala (en espacio local)
  const corners=[
    [-bw/2,-bh/2],[bw/2,-bh/2],[-bw/2,bh/2],[bw/2,bh/2],
    [0,-bh/2],[0,bh/2],[-bw/2,0],[bw/2,0],
  ];
  for(const [hx,hy] of corners){
    edCtx.beginPath(); edCtx.arc(hx,hy,hr,0,Math.PI*2);
    edCtx.fillStyle='#fff'; edCtx.fill();
    edCtx.strokeStyle='#1a8cff'; edCtx.lineWidth=lw*1.5; edCtx.stroke();
  }
  // Handle de rotación — línea + círculo + flecha
  const rotY = -bh/2 - 28/z;
  edCtx.beginPath(); edCtx.moveTo(0,-bh/2); edCtx.lineTo(0,rotY+hrRot);
  edCtx.strokeStyle='#1a8cff'; edCtx.lineWidth=lw; edCtx.stroke();
  edCtx.beginPath(); edCtx.arc(0,rotY,hrRot,0,Math.PI*2);
  edCtx.fillStyle='#1a8cff'; edCtx.fill();
  edCtx.strokeStyle='#fff'; edCtx.lineWidth=lw*1.5; edCtx.stroke();
  edCtx.strokeStyle='#fff'; edCtx.lineWidth=lw*1.5;
  const ar=hrRot*0.55;
  edCtx.beginPath(); edCtx.arc(0,rotY,ar,-Math.PI*0.9,Math.PI*0.5); edCtx.stroke();
  const ax=ar*Math.cos(Math.PI*0.5), ay=rotY+ar*Math.sin(Math.PI*0.5);
  edCtx.beginPath();
  edCtx.moveTo(ax,ay); edCtx.lineTo(ax-3/z,ay-5/z);
  edCtx.moveTo(ax,ay); edCtx.lineTo(ax+4/z,ay-3/z);
  edCtx.stroke();

  edCtx.restore();

  // Marquesina de selección activa
  if(edRubberBand){
    const rx=edMarginX()+Math.min(edRubberBand.x0,edRubberBand.x1)*pw;
    const ry=edMarginY()+Math.min(edRubberBand.y0,edRubberBand.y1)*ph;
    const rw=Math.abs(edRubberBand.x1-edRubberBand.x0)*pw;
    const rh=Math.abs(edRubberBand.y1-edRubberBand.y0)*ph;
    edCtx.strokeStyle='#1a8cff'; edCtx.lineWidth=1.5/z;
    edCtx.setLineDash([5/z,3/z]);
    edCtx.fillStyle='rgba(26,140,255,0.06)';
    edCtx.fillRect(rx,ry,rw,rh); edCtx.strokeRect(rx,ry,rw,rh);
    edCtx.setLineDash([]);
  }
  edCtx.restore();
}

// Dibuja solo la marquesina (cuando aún no hay selección)
function edDrawRubberBand(){
  if(!edRubberBand) return;
  const pw=edPageW(),ph=edPageH(),z=edCamera.z;
  const rx=edMarginX()+Math.min(edRubberBand.x0,edRubberBand.x1)*pw;
  const ry=edMarginY()+Math.min(edRubberBand.y0,edRubberBand.y1)*ph;
  const rw=Math.abs(edRubberBand.x1-edRubberBand.x0)*pw;
  const rh=Math.abs(edRubberBand.y1-edRubberBand.y0)*ph;
  edCtx.save();
  edCtx.strokeStyle='#1a8cff'; edCtx.lineWidth=1.5/z;
  edCtx.setLineDash([5/z,3/z]);
  edCtx.fillStyle='rgba(26,140,255,0.06)';
  edCtx.fillRect(rx,ry,rw,rh); edCtx.strokeRect(rx,ry,rw,rh);
  edCtx.setLineDash([]);
  edCtx.restore();
}

function _msClear(){
  edMultiSel=[]; edMultiDragging=false; edMultiResizing=false; edMultiRotating=false;
  edRubberBand=null; edMultiDragOffs=[]; edMultiTransform=null; edMultiGroupRot=0;
  edMultiBbox=null; edMultiSelAnchor=-1;
  // Limpiar siempre el botón y el dropdown para que no queden activos en PC
  $('edMultiSelBtn')?.classList.remove('active');
  $('_edMultiSelDd')?.classList.remove('open');
}

function _edDeactivateMultiSel(){
  const prev=edMultiSel.length===1?edMultiSel[0]:-1;
  _msClear();
  edActiveTool='select';
  if(edCanvas) edCanvas.className='';
  const btn = document.getElementById('edMultiSelBtn');
  if(btn) btn.classList.remove('active');
  $('_edMultiSelDd')?.classList.remove('open');
  $('dd-select')?.classList.remove('open');
  document.querySelector('[data-menu="select"]')?.classList.remove('open');
  if(edMenuOpen==='select') edMenuOpen=null;
  if(prev>=0&&prev<edLayers.length) edSelectedIdx=prev;
  edRedraw();
}

function _edUpdateMultiSelPanel(){
  // Ya no abre dropdown automáticamente — las opciones se acceden vía botón "Selección ▾"
  const panel=$('edOptionsPanel');
  if(panel && panel.dataset.mode==='multiselect'){ panel.classList.remove('open'); panel.innerHTML=''; delete panel.dataset.mode; }
}

// Actualiza el estado de los items del dropdown Selección ▾ según la selección actual.
// Se llama desde edToggleMenu('select') justo antes de mostrar el menú.
function _edUpdateSelectMenu(){
  const _hasSel = edActiveTool==='multiselect' && edMultiSel.length >= 2;
  const _mergeTypes = _hasSel ? _edMergeableTypes() : null;
  const _dis = 'opacity:0.35;cursor:not-allowed;pointer-events:none';
  // Objetos seleccionables (no ocultos, no capas vinculadas)
  const _selectable = edLayers.filter(la => la && !la.hidden && la.type!=='fill' && la.type!=='pencil' && la.type!=='watercolor');
  const _canSelAll = _selectable.length >= 1;
  const _canDesel  = (edActiveTool==='multiselect' && edMultiSel.length > 0) || edSelectedIdx >= 0;
  const _btnAll  = $('_sel-all');
  const _btnNone = $('_sel-none');
  const _btnGroup = $('_sel-group');
  const _btnMerge = $('_sel-merge');
  const _btnDel   = $('_sel-delete');
  if(_btnAll)  _btnAll .setAttribute('style', _canSelAll ? '' : _dis);
  if(_btnNone) _btnNone.setAttribute('style', _canDesel  ? '' : _dis);
  const _btnDl = $('dd-exportselbtn');
  if(_btnDl)  _btnDl .setAttribute('style', _canDesel  ? '' : _dis);
  if(_btnGroup) _btnGroup.setAttribute('style', _hasSel ? '' : _dis);
  if(_btnMerge) _btnMerge.style.display = (_hasSel && _mergeTypes) ? '' : 'none';
  if(_btnDel)   _btnDel.setAttribute('style', _hasSel ? 'color:#c00' : 'color:#c00;' + _dis);
}

// Recalcula edMultiBbox en espacio LOCAL del grupo (desrotado por edMultiGroupRot).
// Es el ÚNICO sitio que escribe en edMultiBbox.
// Llamar: al confirmar rubber band, al soltar rotate, al soltar resize, al soltar drag.
function _msRecalcBbox(){
  if(!edMultiSel.length){ edMultiBbox=null; return; }
  const pw=edPageW(), ph=edPageH();
  const gr = edMultiGroupRot * Math.PI / 180;
  const cg = Math.cos(-gr), sg = Math.sin(-gr);
  // Centroide de los centros de los objetos (excluir DrawLayer — siempre x=0.5,y=0.5)
  let pivX=0, pivY=0, n=0;
  for(const i of edMultiSel){
    const la=edLayers[i]; if(!la || la.type==='draw') continue;
    pivX+=la.x; pivY+=la.y; n++;
  }
  if(!n){ edMultiBbox=null; return; }
  pivX/=n; pivY/=n;
  // AABB de todos los vértices desrotados al espacio local del grupo
  // DrawLayer ocupa siempre toda la página (width=1, height=1) — excluirlo del bbox
  let x0=Infinity,y0=Infinity,x1=-Infinity,y1=-Infinity;
  for(const i of edMultiSel){
    const la=edLayers[i]; if(!la || la.type==='draw') continue;
    const rot=(la.rotation||0)*Math.PI/180;
    const hw=la.width/2, hh=la.height/2;
    for(const [lcx,lcy] of [[-hw,-hh],[hw,-hh],[-hw,hh],[hw,hh]]){
      const wx=lcx*pw, wy=lcy*ph;
      const vx = la.x + (wx*Math.cos(rot)-wy*Math.sin(rot))/pw;
      const vy = la.y + (wx*Math.sin(rot)+wy*Math.cos(rot))/ph;
      const dx=(vx-pivX)*pw, dy=(vy-pivY)*ph;
      const lx = pivX + (dx*cg - dy*sg)/pw;
      const ly = pivY + (dx*sg + dy*cg)/ph;
      x0=Math.min(x0,lx); y0=Math.min(y0,ly);
      x1=Math.max(x1,lx); y1=Math.max(y1,ly);
    }
  }
  // Centro del bbox local → rotar al espacio global
  const lcxC=(x0+x1)/2, lcyC=(y0+y1)/2;
  const dcx=(lcxC-pivX)*pw, dcy=(lcyC-pivY)*ph;
  const cr=Math.cos(gr), sr=Math.sin(gr);
  const gcx = pivX + (dcx*cr - dcy*sr)/pw;
  const gcy = pivY + (dcx*sr + dcy*cr)/ph;
  edMultiBbox = {
    w:  x1-x0,
    h:  y1-y0,
    cx: gcx,
    cy: gcy,
    // offset centro→centroide en espacio LOCAL rotado (fracción de página)
    // se aplica durante drag para mover el marco sin recalcular todo
    offX: (lcxC - pivX),
    offY: (lcyC - pivY),
  };
}


/* ══════════════════════════════════════════
   T1: Render de grupo de fusión con evenodd en tiempo real
   Combina todos los objetos del grupo en un único Path2D con evenodd
   ══════════════════════════════════════════ */
function _edRenderFusionGroup(ctx, members, alpha) {
  if (!members || members.length === 0) return;
  const pw = edPageW(), ph = edPageH();
  const mx = edMarginX(), my = edMarginY();

  // Usar propiedades visuales del primer miembro
  const _ref = members[0];
  const col      = _ref.color     || '#000000';
  const fillCol  = _ref.fillColor || 'none';
  const lw       = _ref.lineWidth ?? 3;

  ctx.save();
  ctx.globalAlpha = alpha;

  // Construir Path2D combinado con todos los contornos
  const combined = new Path2D();

  members.forEach(m => {
    if (m.type === 'line') {
      // LineLayer: obtener puntos absolutos y construir contornos
      const rot = (m.rotation || 0) * Math.PI / 180;
      const cos = Math.cos(rot), sin = Math.sin(rot);
      const cx = mx + m.x * pw, cy = my + m.y * ph;

      // Separar en contornos (null = separador)
      const contours = [];
      let cur = [];
      for (const p of m.points) {
        if (p === null) { if (cur.length >= 2) contours.push(cur); cur = []; }
        else cur.push(p);
      }
      if (cur.length >= 2) contours.push(cur);

      contours.forEach(c => {
        if (c.length < 2) return;
        combined.moveTo(cx + (c[0].x*pw*cos - c[0].y*ph*sin), cy + (c[0].x*pw*sin + c[0].y*ph*cos));
        for (let i = 1; i < c.length; i++) {
          combined.lineTo(cx + (c[i].x*pw*cos - c[i].y*ph*sin), cy + (c[i].x*pw*sin + c[i].y*ph*cos));
        }
        combined.closePath();
      });
    } else if (m.type === 'shape' && m.shape === 'rect') {
      // ShapeLayer rect: añadir rectángulo
      const rot = (m.rotation || 0) * Math.PI / 180;
      const cx = mx + m.x * pw, cy = my + m.y * ph;
      const hw = m.width * pw / 2, hh = m.height * ph / 2;
      const cos = Math.cos(rot), sin = Math.sin(rot);
      const corners = [[-hw,-hh],[hw,-hh],[hw,hh],[-hw,hh]];
      combined.moveTo(cx + corners[0][0]*cos - corners[0][1]*sin, cy + corners[0][0]*sin + corners[0][1]*cos);
      for (let i = 1; i < 4; i++) {
        combined.lineTo(cx + corners[i][0]*cos - corners[i][1]*sin, cy + corners[i][0]*sin + corners[i][1]*cos);
      }
      combined.closePath();
    } else if (m.type === 'shape' && m.shape === 'ellipse') {
      // ShapeLayer ellipse (por si acaso queda alguno)
      const rot = (m.rotation || 0) * Math.PI / 180;
      const cx = mx + m.x * pw, cy = my + m.y * ph;
      const N = 32;
      const hw = m.width * pw / 2, hh = m.height * ph / 2;
      const cos = Math.cos(rot), sin = Math.sin(rot);
      for (let i = 0; i <= N; i++) {
        const a = (i / N) * Math.PI * 2;
        const lx = Math.cos(a) * hw, ly = Math.sin(a) * hh;
        const wx = cx + lx*cos - ly*sin, wy = cy + lx*sin + ly*cos;
        if (i === 0) combined.moveTo(wx, wy); else combined.lineTo(wx, wy);
      }
      combined.closePath();
    }
  });

  // Rellenar con evenodd
  if (fillCol && fillCol !== 'none') {
    ctx.fillStyle = fillCol;
    ctx.fill(combined, 'evenodd');
  }
  // Trazar borde
  if (lw > 0) {
    ctx.strokeStyle = col;
    ctx.lineWidth = lw;
    ctx.lineJoin = 'round';
    ctx.stroke(combined);
  }

  ctx.restore();
}


/* T1: Fusión inmediata — incorporar nuevo LineLayer al objeto principal de _fusionId */
function _edFuseIntoMain(newLL) {
  if (!_edLineFusionId || !newLL) return newLL;
  // Buscar objeto principal (el primero en edLayers con _fusionId, distinto del nuevo)
  const _primary = edLayers.find(l => l !== newLL && l._fusionId === _edLineFusionId && l.type === 'line');
  if (!_primary) {
    // Primer objeto — es el principal
    newLL._fusionId = _edLineFusionId;
    return newLL;
  }
  // Fusionar: convertir puntos del nuevo al espacio local del principal
  const _rot = -(_primary.rotation || 0) * Math.PI / 180;
  const _cos = Math.cos(_rot), _sin = Math.sin(_rot);
  const _newAbs = newLL.absPoints();
  const _newLocal = _newAbs.map(p => {
    if (!p) return null;
    const dx = p.x - _primary.x, dy = p.y - _primary.y;
    return { x: dx * _cos - dy * _sin, y: dx * _sin + dy * _cos };
  });
  // Concatenar con null separador
  _primary.points.push(null);
  _primary.points.push(..._newLocal);
  _primary._updateBbox();
  // Eliminar el nuevo de edLayers
  const _ni = edLayers.indexOf(newLL);
  if (_ni >= 0) edLayers.splice(_ni, 1);
  return _primary;
}

