  // ── Barra de recorrido de animación (edMotionBar) ──
  $('mpb-play')?.addEventListener('click', () => {
    if (_edMotionPathPlaying) {
      _edMpPreviewStop();
    } else {
      if (!_edMotionPathPts || _edMotionPathPts.length < 2) return; // no hay recorrido
      _edMotionPathPlaying = true;
      const _pla = edLayers[_edMotionPathTarget];
      if (_pla) {
        _pla._pathStartTime = Date.now(); // reiniciar recorrido desde el inicio
        // Arrancar también la animación sincronizada con el recorrido
        if (_pla.type === 'gif' && _pla._ready) {
          _pla._fIdx = 0; _pla._playing = true; _pla._applyFrame(0);
        } else if (_pla.type === 'image' && (_pla._animReady || _pla._apngSrc || _pla._pngFrames)) {
          _pla._fIdx = 0; _pla._gcpPlayCount = 0; _pla._playing = true;
          if (_pla._animReady && _pla._animFrames?.length) {
            _pla._applyFrame(0);
          } else if (_pla._apngSrc || _pla._pngFrames) {
            _pla.loadAnim(_pla._apngSrc || _pla._pngFrames, () => { if (_pla._playing) _pla._applyFrame(0); });
          }
        }
      }
      const btn = $('mpb-play'); if (btn) btn.textContent = '⏹';
      _edMpPreviewRaf = requestAnimationFrame(_edMpPreviewTick);
    }
  });
  $('mpb-speed')?.addEventListener('input', (e) => {
    _edMotionPathSpeed = +e.target.value;
    const _msv = $('mpb-speed-val'); if (_msv) _msv.textContent = _edMotionPathSpeed + 'px/s';
    if (_edMotionPathPlaying) { const _pla = edLayers[_edMotionPathTarget]; if (_pla) _pla._pathStartTime = Date.now(); }
  });
  $('mpb-cycles')?.addEventListener('input', (e) => {
    _edMotionPathCycles = Math.max(1, Math.round(parseFloat(e.target.value) || 1));
    const _pla2 = edLayers[_edMotionPathTarget];
    const _cDur2 = _pla2 ? _edGetCycleDurationMs(_pla2) : 0;
    const _cdv2 = $('mpb-cycles-dur');
    if (_cdv2) _cdv2.textContent = _cDur2 > 0 ? '≈' + (_edMotionPathCycles * _cDur2 / 1000).toFixed(1) + 's' : '';
    if (_edMotionPathPlaying) { const _pla3 = edLayers[_edMotionPathTarget]; if (_pla3) _pla3._pathStartTime = Date.now(); }
    _edUpdateBubble(e.target, '×');
  });
  $('mpb-undo')?.addEventListener('click', () => {
    // Borrar el trayecto dibujado para poder redibujarlo
    _edMotionPathPts = []; _edMotionPathRaw = []; _edMotionPathDrawing = false; edRedraw();
  });
  $('mpb-ok')?.addEventListener('click', () => _edEndMotionPath(true));
  $('mpb-cancel')?.addEventListener('click', () => _edEndMotionPath(false));

  // ── Botón Comportamiento de la barra de recorrido ─────────────────────────
  $('mpb-behaviour')?.addEventListener('click', () => {
    const _modal = $('edMpBehaviourModal');
    if (!_modal) return;
    if (_modal.classList.contains('open')) { _mpbehClose(); return; }
    // Pre-seleccionar comportamiento actual de la capa
    const _mla = edLayers[_edMotionPathTarget];
    const _curEnd    = _mla?._motionPathEnd   || 'restart';
    const _curAccel  = _mla?._motionPathAccel || 'none';
    const _curOrient = _mla?._motionPathOrient ? 'path' : 'fixed';
    document.querySelectorAll('[data-mpbeh-end]').forEach(b => {
      b.classList.toggle('active', b.dataset.mpbehEnd === _curEnd);
    });
    document.querySelectorAll('[data-mpbeh-accel]').forEach(b => {
      b.classList.toggle('active', b.dataset.mpbehAccel === _curAccel);
    });
    document.querySelectorAll('[data-mpbeh-orient]').forEach(b => {
      b.classList.toggle('active', b.dataset.mpbehOrient === _curOrient);
    });
    _modal.classList.add('open');
  });

  // ── Modal Comportamiento del Recorrido ────────────────────────────────────
  // (el modal vive fuera de editorShell → los eventos no son interceptados por el canvas)
  {
    const _mpbehModal = $('edMpBehaviourModal');

    // Cerrar con X, Cancelar u OK
    $('mpbeh-close')?.addEventListener('click',  _mpbehClose);
    $('mpbeh-cancel')?.addEventListener('click', _mpbehClose);
    $('mpbeh-ok')?.addEventListener('click', () => {
      const _mbLa = edLayers[_edMotionPathTarget];
      if (_mbLa) {
        const _endBtn    = document.querySelector('[data-mpbeh-end].active');
        const _accelBtn  = document.querySelector('[data-mpbeh-accel].active');
        const _orientBtn = document.querySelector('[data-mpbeh-orient].active');
        const _endVal    = _endBtn    ? _endBtn.dataset.mpbehEnd     : 'restart';
        const _accelVal  = _accelBtn  ? _accelBtn.dataset.mpbehAccel : 'none';
        const _orientVal = _orientBtn ? _orientBtn.dataset.mpbehOrient === 'path' : false;
        _mbLa._motionPathEnd    = _endVal;
        _mbLa._motionPathAccel  = _accelVal;
        _mbLa._motionPathOrient = _orientVal;
        // Al desactivar orientación, limpiar el giro que pudiera seguir visible
        if (!_orientVal) delete _mbLa._pathCurRotDeg;
        if (_mbLa.groupId) {
          _edGroupMemberIdxs(_mbLa.groupId).forEach(i => {
            const _gm = edLayers[i];
            if (_gm) {
              _gm._motionPathEnd = _endVal; _gm._motionPathAccel = _accelVal;
              _gm._motionPathOrient = _orientVal;
              if (!_orientVal) delete _gm._pathCurRotDeg;
            }
          });
        }
        edPushHistory();
      }
      _mpbehClose();
    });

    // Cerrar al tocar el fondo del overlay (fuera del box)
    _mpbehModal?.addEventListener('pointerdown', (e) => {
      if (e.target === _mpbehModal) _mpbehClose();
    });

    // Toggle sección "Al final del recorrido"
    $('mpbeh-end-toggle')?.addEventListener('click', () => {
      const _sec = $('mpbeh-end-toggle').closest('.mpbeh-section');
      const _isOpen = _sec.classList.contains('open');
      document.querySelectorAll('#edMpBehaviourModal .mpbeh-section').forEach(s => s.classList.remove('open'));
      if (!_isOpen) _sec.classList.add('open');
    });

    // Toggle sección "Aceleraciones"
    $('mpbeh-accel-toggle')?.addEventListener('click', () => {
      const _sec = $('mpbeh-accel-toggle').closest('.mpbeh-section');
      const _isOpen = _sec.classList.contains('open');
      document.querySelectorAll('#edMpBehaviourModal .mpbeh-section').forEach(s => s.classList.remove('open'));
      if (!_isOpen) _sec.classList.add('open');
    });

    // Toggle sección "Orientación del objeto"
    $('mpbeh-orient-toggle')?.addEventListener('click', () => {
      const _sec = $('mpbeh-orient-toggle').closest('.mpbeh-section');
      const _isOpen = _sec.classList.contains('open');
      document.querySelectorAll('#edMpBehaviourModal .mpbeh-section').forEach(s => s.classList.remove('open'));
      if (!_isOpen) _sec.classList.add('open');
    });

    // Selección de opción "Al final del recorrido"
    document.querySelectorAll('[data-mpbeh-end]').forEach(btn => {
      btn.addEventListener('click', () => {
        document.querySelectorAll('[data-mpbeh-end]').forEach(b => b.classList.remove('active'));
        btn.classList.add('active');
      });
    });

    // Selección de opción "Aceleraciones"
    document.querySelectorAll('[data-mpbeh-accel]').forEach(btn => {
      btn.addEventListener('click', () => {
        document.querySelectorAll('[data-mpbeh-accel]').forEach(b => b.classList.remove('active'));
        btn.classList.add('active');
      });
    });

    // Selección de opción "Orientación del objeto"
    document.querySelectorAll('[data-mpbeh-orient]').forEach(btn => {
      btn.addEventListener('click', () => {
        document.querySelectorAll('[data-mpbeh-orient]').forEach(b => b.classList.remove('active'));
        btn.classList.add('active');
      });
    });
  }

  // ── Drag de la barra de recorrido ─────────────────────────────────────────
  {
    const _mpBar = $('edMotionBar');
    const _mpHandle = $('mpb-drag');
    if (_mpBar && _mpHandle) {
      let _mpDragging = false, _mpDx = 0, _mpDy = 0, _mpBL = 0, _mpBT = 0;
      const _mpDragStart = (e) => {
        if (e.button !== undefined && e.button !== 0) return;
        e.stopPropagation(); e.preventDefault();
        _mpDragging = true;
        _mpHandle.style.cursor = 'grabbing';
        // Convertir la posición actual (puede tener translateX(-50%)) a píxeles absolutos
        const _r = _mpBar.getBoundingClientRect();
        _mpBL = _r.left; _mpBT = _r.top;
        _mpBar.style.left = _mpBL + 'px';
        _mpBar.style.top  = _mpBT + 'px';
        _mpBar.style.transform = 'none';
        _mpDx = e.clientX - _mpBL; _mpDy = e.clientY - _mpBT;
        _mpHandle.setPointerCapture(e.pointerId);
      };
      const _mpDragMove = (e) => {
        if (!_mpDragging) return;
        e.stopPropagation(); e.preventDefault();
        const _newL = Math.max(0, Math.min(window.innerWidth  - _mpBar.offsetWidth,  e.clientX - _mpDx));
        const _newT = Math.max(0, Math.min(window.innerHeight - _mpBar.offsetHeight, e.clientY - _mpDy));
        _mpBar.style.left = _newL + 'px';
        _mpBar.style.top  = _newT + 'px';
      };
      const _mpDragEnd = (e) => {
        if (!_mpDragging) return;
        _mpDragging = false;
        _mpHandle.style.cursor = 'grab';
        e.stopPropagation();
      };
      _mpHandle.addEventListener('pointerdown', _mpDragStart);
      _mpHandle.addEventListener('pointermove', _mpDragMove);
      _mpHandle.addEventListener('pointerup',   _mpDragEnd);
      _mpHandle.addEventListener('pointercancel', _mpDragEnd);
    }
  }

  $('dd-cleardraw')?.addEventListener('click',()=>{edClearDraw();edCloseMenus();});

